<Sequence>
  <Action1/>
  <Action2/>
</Sequence>

<!-- Fallback: One must succeed -->
<Fallback>
  <Option1/>
  <Option2/>
</Fallback>

<!-- Parallel: Concurrent execution -->
<Parallel success_threshold="2">
  <Task1/>
  <Task2/>
</Parallel>
